    SecureController() : Node("secure_controller") {
        sub_ = create_subscription<custom_msgs::msg::AuthenticatedCommand>(
            "authenticated_cmd", 10,
            [this](const custom_msgs::msg::AuthenticatedCommand::SharedPtr msg) {
